// Parse the CGA HTML page and extract hearing information
const html = $input.first().json.data || $input.first().json.body || '';

// Extract text content — strip HTML tags for keyword matching
const textContent = html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ');

// Split into potential hearing blocks
// CGA pages typically list hearings with date, committee, and subject
const lines = textContent.split(/(?=\d{1,2}\/\d{1,2}\/\d{2,4})/g);

const keywords = [
  'staffing ratio', 'collective bargaining', 'healthcare worker',
  'wages and hours', 'nurse staffing', 'hospital worker',
  'SEBAC', '1199', 'AFSCME', 'labor', 'health care',
  'nursing', 'wage', 'bargaining unit', 'union'
];

const hearings = [];
for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed || trimmed.length < 20) continue;

  const lowerLine = trimmed.toLowerCase();
  const matchedKeywords = keywords.filter(kw => lowerLine.includes(kw.toLowerCase()));

  if (matchedKeywords.length > 0) {
    // Try to extract a date
    const dateMatch = trimmed.match(/(\d{1,2}\/\d{1,2}\/\d{2,4})/);
    hearings.push({
      json: {
        raw_text: trimmed.substring(0, 500),
        date: dateMatch ? dateMatch[1] : 'unknown',
        matched_keywords: matchedKeywords,
        keyword_count: matchedKeywords.length
      }
    });
  }
}

if (hearings.length === 0) {
  return [{
    json: {
      raw_text: 'No hearings matching healthcare labor keywords found this week.',
      date: 'N/A',
      matched_keywords: [],
      keyword_count: 0,
      no_results: true
    }
  }];
}

return hearings;

// Aggregate all hearings into a single prompt for Ollama
const hearings = $input.all().map((item, i) => {
  return `Hearing ${i+1}:\n  Date: ${item.json.date}\n  Matched keywords: ${item.json.matched_keywords.join(', ')}\n  Details: ${item.json.raw_text}`;
});

const prompt = `You are a legislative analyst for a healthcare workers union (CHCA, District 1199NE, AFSCME) in Connecticut. Briefly summarize these CT legislative hearings relevant to healthcare labor. Rate each high/medium/low relevance. Be concise.\n\n${hearings.join('\n\n')}`;

return [{
  json: {
    prompt: prompt,
    hearing_count: hearings.length,
    hearings_raw: $input.all().map(i => i.json)
  }
}];

// Build tasks for each relevant hearing to post to Pulse
const ollamaResponse = $('Ollama Summarize Hearings').first().json.response || '';
const hearingsRaw = $('Build Ollama Prompt').first().json.hearings_raw || [];

const tasks = hearingsRaw.map((hearing, i) => {
  return {
    json: {
      title: `Legislative hearing: ${hearing.date} — ${hearing.matched_keywords.slice(0, 3).join(', ')}`,
      description: hearing.raw_text.substring(0, 300),
      tag: 'legislative',
      assigned_to: 'dave',
      priority: hearing.keyword_count >= 3 ? 'high' : 'medium',
      ai_summary: ollamaResponse,
      source: 'CT General Assembly',
      hearing_date: hearing.date
    }
  };
});

return tasks.length > 0 ? tasks : [{ json: { skip: true } }];

